css:
:root{
--bg:#050509;--s1:#0c0c15;--s2:#131320;--s3:#1b1b2e;
--brd:#222240;--brd2:#333358;
--tx:#d0d0e6;--tx2:#8888aa;--tx3:#5e5e80;
--w:#f2f2ff;
--js:#f7df1e;--js-bg:rgba(247,223,30,.06);
--react:#61dafb;--react-bg:rgba(97,218,251,.06);
--next:#fff;--next-bg:rgba(255,255,255,.04);
--ng:#dd0031;--ng-bg:rgba(221,0,49,.06);
--green:#34d399;--red:#f87171;--yellow:#fbbf24;--purple:#a78bfa;--blue:#60a5fa;--pink:#f472b6;
--code-bg:#08080f;
--r:10px;
}
*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{font-family:'Manrope',sans-serif;background:var(--bg);color:var(--tx);line-height:1.72;font-size:14.5px;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg)}::-webkit-scrollbar-thumb{background:var(--purple);border-radius:9px}

/* HERO */
.hero{padding:3rem 1.5rem 1.5rem;text-align:center;position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 80% 60% at 50% -10%,rgba(167,139,250,.1),transparent 60%);pointer-events:none}
.hero h1{font-family:'Literata',serif;font-size:clamp(1.8rem,5vw,3.4rem);font-weight:900;color:var(--w);letter-spacing:-.03em;line-height:1.15;position:relative}
.hero .techs{display:flex;gap:1.5rem;justify-content:center;margin-top:1rem;flex-wrap:wrap}
.hero .tech{font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.1em;padding:.35rem .8rem;border-radius:20px;border:1px solid}
.t-js{color:var(--js);border-color:rgba(247,223,30,.3);background:var(--js-bg)}
.t-react{color:var(--react);border-color:rgba(97,218,251,.3);background:var(--react-bg)}
.t-next{color:var(--next);border-color:rgba(255,255,255,.15);background:var(--next-bg)}
.t-ng{color:var(--ng);border-color:rgba(221,0,49,.3);background:var(--ng-bg)}
.hero .sub{color:var(--tx2);margin-top:.8rem;font-size:.9rem}

/* TOP TABS */
.top-tabs{display:flex;justify-content:center;gap:.5rem;padding:.75rem 1rem;flex-wrap:wrap;border-bottom:1px solid var(--brd);position:sticky;top:0;z-index:1000;background:rgba(5,5,9,.9);backdrop-filter:blur(20px)}
.top-tab{font-family:'Manrope',sans-serif;font-size:.82rem;font-weight:700;padding:.55rem 1.25rem;border-radius:8px;border:1px solid var(--brd);background:var(--s1);color:var(--tx2);cursor:pointer;transition:.2s}
.top-tab:hover{border-color:var(--tx3);color:var(--tx)}
.top-tab.active{color:var(--w)}
.top-tab[data-t="js"].active{background:rgba(247,223,30,.1);border-color:var(--js);color:var(--js)}
.top-tab[data-t="react"].active{background:rgba(97,218,251,.1);border-color:var(--react);color:var(--react)}
.top-tab[data-t="next"].active{background:rgba(255,255,255,.08);border-color:rgba(255,255,255,.4);color:var(--w)}
.top-tab[data-t="ng"].active{background:rgba(221,0,49,.1);border-color:var(--ng);color:var(--ng)}

/* SUB NAV */
.sub-nav{overflow-x:auto;white-space:nowrap;padding:.5rem 1rem;border-bottom:1px solid var(--brd);position:sticky;top:52px;z-index:999;background:rgba(5,5,9,.85);backdrop-filter:blur(16px);-webkit-overflow-scrolling:touch}
.sub-nav::-webkit-scrollbar{height:0}
.sub-nav-inner{display:flex;gap:0;max-width:1200px;margin:0 auto}
.snav{background:0;border:0;color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.75rem;font-weight:500;padding:.65rem 1rem;cursor:pointer;border-bottom:2px solid transparent;transition:.2s;white-space:nowrap}
.snav:hover{color:var(--tx)}
.snav.active{color:var(--purple);border-bottom-color:var(--purple)}

.main{max-width:860px;margin:0 auto;padding:1.5rem 1.25rem 6rem}

/* TECH SECTIONS */
.tech-section{display:none}.tech-section.active{display:block}
.section{display:none;animation:fadeUp .3s ease}.section.active{display:block}
@keyframes fadeUp{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}

.section-intro{font-size:.95rem;color:var(--tx2);margin-bottom:1.5rem;padding-bottom:1.25rem;border-bottom:1px solid var(--brd)}

/* CARDS */
.card{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);padding:1.6rem;margin-bottom:1.15rem;transition:border-color .3s}
.card:hover{border-color:var(--brd2)}
.card h2{font-family:'Literata',serif;font-size:1.35rem;font-weight:700;color:var(--w);margin-bottom:.7rem}
.card h3{font-size:1rem;font-weight:700;color:var(--green);margin:1.3rem 0 .5rem}
.card h4{font-size:.88rem;font-weight:600;color:var(--purple);margin:1.1rem 0 .4rem}

/* CODE */
pre{background:var(--code-bg);border:1px solid var(--brd);border-radius:8px;padding:1.1rem;overflow-x:auto;margin:.55rem 0;font-size:.78rem;line-height:1.65;tab-size:2}
code{font-family:'JetBrains Mono',monospace;font-size:.78rem}
p code,li code{background:var(--s2);padding:.12em .4em;border-radius:4px;color:var(--pink);font-size:.78em}
.kw{color:#c792ea}.st{color:#c3e88d}.cm{color:#546e7a}.fn{color:#82aaff}.dc{color:#ffcb6b}.nu{color:#f78c6c}.ty{color:#f07178}

/* Q&A */
.qa{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);margin-bottom:.55rem;overflow:hidden}
.qa-h{padding:.9rem 1.1rem;cursor:pointer;display:flex;align-items:flex-start;gap:.7rem;user-select:none;transition:background .2s}
.qa-h:hover{background:var(--s2)}
.lvl{font-family:'JetBrains Mono',monospace;font-size:.58rem;font-weight:600;padding:.15rem .5rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.18rem}
.lvl.b{background:rgba(52,211,153,.1);color:var(--green)}
.lvl.i{background:rgba(251,191,36,.1);color:var(--yellow)}
.lvl.a{background:rgba(248,113,113,.1);color:var(--red)}
.qq{font-weight:600;font-size:.87rem;color:var(--w);flex:1}
.tog{color:var(--tx3);font-size:1.1rem;flex-shrink:0;transition:transform .3s;margin-top:.05rem}
.qa.open .tog{transform:rotate(45deg)}
.qa-a{max-height:0;overflow:hidden;transition:max-height .45s ease}
.qa.open .qa-a{max-height:9000px}
.qa-ai{padding:0 1.1rem 1.1rem}
.qa-ai p{margin-bottom:.4rem}

/* BOXES */
.analogy{background:rgba(167,139,250,.06);border-left:3px solid var(--purple);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.analogy::before{content:'💡 Remember it like this';display:block;font-weight:700;font-size:.7rem;color:var(--purple);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}
.tip{background:rgba(52,211,153,.06);border-left:3px solid var(--green);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.tip::before{content:'🔥 Pro Tip';display:block;font-weight:700;font-size:.7rem;color:var(--green);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}
.warn{background:rgba(251,191,36,.06);border-left:3px solid var(--yellow);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.warn::before{content:'⚠️ Common Mistake';display:block;font-weight:700;font-size:.7rem;color:var(--yellow);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}

/* FILTER */
.fbar{display:flex;gap:.35rem;margin-bottom:1rem;flex-wrap:wrap}
.fbtn{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.75rem;font-weight:500;padding:.4rem .85rem;border-radius:20px;cursor:pointer;transition:.2s}
.fbtn:hover{border-color:var(--tx3)}
.fbtn.active{background:var(--purple);border-color:var(--purple);color:#fff}
.counter{font-size:.78rem;color:var(--tx3);margin-bottom:.8rem}
.counter b{color:var(--purple)}

ul,ol{padding-left:1.4rem;margin:.4rem 0}li{margin-bottom:.25rem}p{margin-bottom:.45rem}strong{color:var(--w)}

@media(max-width:640px){.card{padding:1.15rem}pre{padding:.85rem;font-size:.72rem}.qa-h{padding:.75rem .9rem}.top-tab{padding:.45rem .9rem;font-size:.75rem}}

scripts:
// Top tech tabs
document.querySelectorAll('.top-tab').forEach(tab => {
  tab.addEventListener('click', () => {
    document.querySelectorAll('.top-tab').forEach(t => t.classList.remove('active'));
    document.querySelectorAll('.tech-section').forEach(s => s.classList.remove('active'));
    tab.classList.add('active');
    document.getElementById('ts-' + tab.dataset.t).classList.add('active');
    // Activate first sub-nav section
    const ts = document.getElementById('ts-' + tab.dataset.t);
    const firstSnav = ts.querySelector('.snav');
    if (firstSnav) {
      ts.querySelectorAll('.snav').forEach(s => s.classList.remove('active'));
      ts.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
      firstSnav.classList.add('active');
      const firstSection = ts.querySelector('.section');
      if (firstSection) firstSection.classList.add('active');
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
});

// Sub-nav within each tech section
document.querySelectorAll('.snav').forEach(btn => {
  btn.addEventListener('click', () => {
    const parent = btn.closest('.tech-section');
    parent.querySelectorAll('.snav').forEach(b => b.classList.remove('active'));
    parent.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
    btn.classList.add('active');
    const target = parent.querySelector('#' + btn.dataset.s);
    if (target) target.classList.add('active');
  });
});

// Q&A toggle
document.querySelectorAll('.qa-h').forEach(h => {
  h.addEventListener('click', () => h.parentElement.classList.toggle('open'));
});

// Filter buttons
function updateCounts(container) {
  const vis = container.querySelectorAll('.qa:not([style*="display: none"])').length;
  const counter = container.querySelector('.vis-count');
  if (counter) counter.textContent = vis;
}

document.querySelectorAll('.fbtn').forEach(btn => {
  btn.addEventListener('click', () => {
    const section = btn.closest('.section');
    section.querySelectorAll('.fbtn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    const f = btn.dataset.f;
    section.querySelectorAll('.qa').forEach(qa => {
      qa.style.display = (f === 'all' || qa.dataset.l === f) ? '' : 'none';
    });
    updateCounts(section);
  });
});

// Init counts
document.querySelectorAll('.section').forEach(s => updateCounts(s));
